#!/usr/bin/env python3

from struct import unpack
from base64 import b64decode
import zlib

data = b''
data = zlib.decompress(b64decode(data))
flag = input()
cur = [unpack('<I', flag[i:i+4].encode("ascii"))[0] for i in range(0, len(flag), 4)]
if cur[0] == 0x7b425448:
    exec(data, {"cur": cur[1:]})
else:
    print("Error!")
